import React from 'react';
import { render } from '@testing-library/react';
import ProductList from './ProductList';

test('renders products', () => {
  const products = [{ id: 1, name: 'Test Product' }];
  const { getByText } = render(<ProductList products={products} />);

  expect(getByText(/Test Product/i)).toBeInTheDocument();
});

import React from 'react';
import { render, fireEvent } from '@testing-library/react';
import UserManagement from './UserManagement';

test('handles login', () => {
  const handleLogin = jest.fn();
  const { getByText } = render(<UserManagement onLogin={handleLogin} />);

  fireEvent.click(getByText(/Login/i));
  expect(handleLogin).toHaveBeenCalled();
});

import React from 'react';
import { render } from '@testing-library/react';
import ShoppingCart from './ShoppingCart';

test('renders cart items', () => {
  const cartItems = [{ id: 1, name: 'Test Item' }];
  const { getByText } = render(<ShoppingCart cartItems={cartItems} />);

  expect(getByText(/Test Item/i)).toBeInTheDocument();
});
